    "    so_date-option = 'BT'.",
    "    so_date-low    = sy-datum.",
    "    so_date-high   = sy-datum + 30.",
    "    APPEND so_date.",
    "  ENDIF.",
    "",
    "*---------------------------------------------------------------------*",
    "* AT SELECTION-SCREEN",
    "*---------------------------------------------------------------------*",
    "AT SELECTION-SCREEN.",
    "  PERFORM frm_validate_input.",
